local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxLoginCtrl:LxBaseCtrl
local LxLoginCtrl = classX("LxLoginCtrl", LxBaseCtrl)

local _LoginSteps = {
    None = 0,
    WebAuth = 1,
    Connect = 2,
    ServerAuth = 3,
    GetServerTime = 4,
    GetRoleData = 5,
    CreateRole = 6,
    GetInitData = 7,

    Done = 99
}

function LxLoginCtrl:Initialize()
    LxBaseCtrl.Initialize(self)

    self._step = _LoginSteps.None
end

function LxLoginCtrl:OnInitLogin()
    self:InitEvents()
end

function LxLoginCtrl:InitEvents()
    self:AddEventHandler(EventNames.NET_CONNECTED, function(progress) self:OnNetConnected() end)
    self:AddEventHandler(EventNames.GAME_PAUSE_CHANGE, function(...) self:OnGamePauseChange(...) end)
    self:AddEventHandler(EventNames.LOGIN_UI_READY, function(...) self:OnLoginUIPrepareOK()  end)
    self:AddEventHandler(EventNames.SDK_LOGOUT_OK, function(...) self:OnSdkLogoutOk()  end)
end

function LxLoginCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

---@region 游戏暂停
function LxLoginCtrl:OnGamePauseChange(pause, holdTime)
    if pause then
        if MgrCenter.NetworkMgr then
            MgrCenter.NetworkMgr:CheckResetNetBlock()
        end
    else
        --大于等于60分钟重启
        if holdTime >= 3600 then
            RestartGame()
            return
        end
        --大于等于20分钟 拉取服务器列表信息
        if holdTime >= 1200 then
            local serverData = gLxServerList:NewServerList()
            self._gamePauseSeverData = serverData
            serverData.ignoreReviewSighChange = true
            serverData:QueryServerListWithCallback(gLxSdkImpl:CallMethod(SdkMethod.GetPackageId),function(resultData, bOk)
                if self._gamePauseSeverData ~= resultData then return end
                if not bOk then return end
                local serverItem = self._gamePauseSeverData:GetServerItem(ModuleCenter.Login:GetLoginServerId())
                if serverItem and serverItem.state ~= 1 then
                    ShowPanel(UiNames.SysAlert, {refId = 19})
                    MgrCenter.NetworkMgr:StopConnect("game pause quit")
                end
                if self:CheckResVersionFormServer(self._gamePauseSeverData.webPackageVersion, true, false) then
                    return
                end
            end)
        end
    end
end

---@endregion 游戏暂停

---@region 服务器通知 的封禁函数
function LxLoginCtrl:DoQuitFromServer(quitType, sessionId)
    --- 0-正常退出,1-服务器关服踢下线,2-被顶号,3-长时间未操作(可以让玩家重连),4-后台强制踢下线,5-服务器内部异常,6-操作过于频繁
---
--    if ModuleCenter.Login:GetSessionId() ~= sessionId then return end
    if quitType == 1 then
        ShowPanel(UiNames.SysAlert, {refId = 19})
    elseif quitType == 2 then
        ShowPanel(UiNames.SysAlert, {refId = 17})
    elseif quitType == 3 then
        ShowPanel(UiNames.SysAlert, {refId = 25, cb = function() MgrCenter.NetworkMgr:RecreateAndConnect() end})
    elseif quitType == 4 or quitType == 0 then
        ShowPanel(UiNames.SysAlert, {refId = 18})
    elseif quitType == 5 then
        ShowPanel(UiNames.SysAlert, {refId = 16})
    end
    MgrCenter.NetworkMgr:StopConnect("server quit")
end

function LxLoginCtrl:CheckResVersionFormServer(serverResVersion, forceUpdate, isFromAuth)
    local appVersion,packageVersion  = LxResUtil.GetActiveVersions()
    local resVersion = LxResUtil.ConvertToVersion(serverResVersion)
    if resVersion:CompareTo(packageVersion) > 0 then
        LogWarn(string.format("server ver=%s, local ver=%s", tostring(resVersion), tostring(packageVersion)))
        if LxGameSettings.resMode == 0  and  isFromAuth then
            --模拟器模式不在登录时候校验版本
            return false
        end
        if isFromAuth then
            ShowPanel(UiNames.SysAlert, {refId= 20})
        elseif forceUpdate then
            ShowPanel(UiNames.SysAlert, {refId= 21})
            MgrCenter.NetworkMgr:StopConnect("res update")
        else
            ShowPanel(UiNames.SysAlert, {refId= 22})
        end

        return true
    end
    return false
end

---@param disableType number @封禁类型,1-封登录账号,2-封角色
---@param disableBeginTime number 封禁开始时间
---@param disableEndTime number -1表示永久
---@param silentBeginTime number 禁言开始时间
---@param silentEndTime number 禁言结束时间.-1表示永久
function LxLoginCtrl:OnDisableFormServer(disableType, disableBeginTime, disableEndTime, silentBeginTime, silentEndTime)
    local curTime = GetTimestamp()
    local delayDisableTime = 0
    local isQuit = true
    if disableType > 0 then
        if disableBeginTime == -1 then
            delayDisableTime = 0
        else
            delayDisableTime = disableBeginTime - curTime
        end
        if disableEndTime == -1 then
            isQuit = true
            ShowPanel(UiNames.SysAlert, {refId=23})
        elseif disableEndTime > curTime then
            isQuit = true
            local timeStr = LxUtil.GetDate(disableEndTime)
            ShowPanel(UiNames.SysAlert, {refId=24, args = timeStr})
        end
    end
    if isQuit then
        MgrCenter.NetworkMgr:StopConnect("disabled resp")
    end
end
---@endregion 服务器通知 的封禁函数

