---回退
function LxLoginCtrl:BackToLogin()
    if not MgrCenter.LevelMgr:IsInLevel(LevelNames.Login) then
        RestartGame()
    else
        ModuleCenter.Login:SetAuthReqTimeoutCount(0)
        MgrCenter.NetworkMgr:ResetShowCounter()
        if self._step ~= _LoginSteps.None   then
            self:SetLoginStep(_LoginSteps.None)
        end

        FireEvent(EventNames.LOGIN_BACK_LOGIN)
    end
end

function LxLoginCtrl:SetLoginStep(step)
    self._step = step
    FireEvent(EventNames.LOGIN_STEP, step)
end

---开始登录
function LxLoginCtrl:StartLogin()
    if self._step ~= _LoginSteps.None then
        --正在登录
        ShowSysMsg(I18nText(1088))
        return
    end

    if not gLxSdkImpl:CallMethod(SdkMethod.IsLogin) then
        self:ShowAuthUI()
        return
    end
    ---@type LxServerItem 保存登录服
    local serverItem =  ModuleCenter.Login:GetLoginServer()
    if not serverItem then
        ShowPanel(UiNames.Server)
        return
    end

    local isWithe = false
    if gLxServerList and gLxServerList:IsWhiteUser() then
        isWithe = true
    end
    if serverItem.state ~= 1 and not isWithe then
        --ShowSysMsg(I18nText(4))
        ShowPanel(UiNames.Alert,
                {refId = 1,
                        actionOk = function()
                            --self:StartLogin()
                            --- 维护状态下 重新尝试进入服务器
                            local serverData = gLxServerList:NewServerList()
                            serverData:QueryServerListWithCallback(gLxSdkImpl:CallMethod(SdkMethod.GetPackageId),function(resultData, bOk)
                                if not bOk then return end
                                local curServerItem = resultData:GetServerItem(ModuleCenter.Login:GetLoginServerId())
                                if curServerItem and curServerItem.state == 1 then
                                    gLxServerList:FixedServerIpData(curServerItem)
                                    ModuleCenter.Login:SetLoginServer(curServerItem)
                                    self:StartLogin()
                                else
                                    ShowPanel(UiNames.Server)
                                end
                            end)
                        end,
                        actionCancel = function()
                            local notice = gLxServerList:GetPlatformNotices()
                            if(table.nums(notice) > 0)then
                                ShowPanel(UiNames.SystemNotice)
                            else
                                ShowSysMsg(I18nText(10305))
                            end
                        end}
                )
        return
    end

    LxPlayerPrefs.serverId = serverItem.id

    if gLxTKData then
        gLxTKData:InitEnableState(serverItem)
    end

    if gLxTKData then
        gLxTKData:BeginLoginGame()
    end
    self:GetHttpAuth()
end

---中心验证获取账号
function LxLoginCtrl:GetHttpAuth()
    self:SetLoginStep(_LoginSteps.WebAuth)
    -- 从中心服获取账号
    RefreshPanel(UiNames.Login, {type = 2})
    local sdkUserId = ModuleCenter.Login:GetAccount()

    local serverItem =  ModuleCenter.Login:GetLoginServer()
    local serverId = serverItem.id
    local channelId = gLxServerList:GetChannelId()

    local mergeToSvr = nil
    local isRealName = nil
    local uuid = LxPlayerPrefs.uuid
    local time = PJXUtil.GetTime()
    local datas = {
        serverId = serverId,
        channelId = channelId,
        sdkUserId = sdkUserId,
        mergeToSvr = mergeToSvr,
        isRealName = isRealName,
        uuid = uuid,
        time = time,
    }
    local retNameList = {"channelId", "isRealName", "mergeToSvr", "sdkUserId", "serverId", "time", "uuid"}
    local signDatas = {}
    for k,name in ipairs(retNameList) do
        local v = datas[name]
        if v ~= nil then
            v = tostring(v)
            if not string.isempty(v) then
                table.insert(signDatas, name.."="..v)
            end
        end
    end

    table.insert(signDatas, "secret="..gLxServerList.client_secret)
    local sign = PJXUtil.md5(table.concat(signDatas, "&"))
    table.remove(signDatas)
    table.insert(signDatas, "sign="..sign)

    local sendStr = table.concat(signDatas, "&")

    local authUrl = gLxServerList.authUrl
    if not string.isempty(authUrl) then
        if not string.startswith(authUrl, "/") then
            authUrl = "/"..authUrl
        end
    else
        authUrl = "/client/user/login"
    end

    local urlName = authUrl.."?"..sendStr

    local serverUrl = { LxGameSettings.url1 .. urlName, LxGameSettings.url2 .. urlName}
    ShowBlockMask(true)
    MgrCenter.HttpMgr:DoPost(serverUrl, function(url, ret, data)
        ShowBlockMask(false)
        if self:IsDisposed() then return end

        if LOG_INFO_ENABLED then
            printInfo("web", FormatLogWithColor(data, "ff00ffff"))
            printInfo("web", "ret "..tostring(ret))
        end

        if ret then
            local resultTbl = CJSON.decode(data)
            if not resultTbl then
                if LOG_INFO_ENABLED then
                    printError("login", "error for decode json")
                end
                self:BackToLogin()
                ShowSysMsg(I18nText(1091))
                return
            end
            if resultTbl.code ~= 0 then
                if LOG_INFO_ENABLED then
                    printError("login", "error , code = "..tostring(resultTbl.code))
                end
                self:BackToLogin()
                ShowSysMsg(I18nText(1089, resultTbl.code))
                return
            end
            local retData = resultTbl.data
            if retData.sdkUserId ~= ModuleCenter.Login:GetAccount() then
                if LOG_INFO_ENABLED then
                    printError("login", "SdkUserId is not same,  %s = %s", tostring(retData.sdkUserId), tostring(ModuleCenter.Login:GetAccount()))
                end
                self:BackToLogin()
                return
            end
            ModuleCenter.Login:SetLoginIdentityId(retData.identityId)
            ModuleCenter.Login.httpAuthResponseData = retData
            ModuleCenter.Login:SetLoginGateWayInfo(retData.gatewayInfo)
            self:ConnectServer()
        else
            self:BackToLogin()
            ShowSysMsg(I18nText(1090))
        end
    end)
end

---连接服务器
function LxLoginCtrl:ConnectServer()
    self:SetLoginStep(_LoginSteps.Connect)
    RefreshPanel(UiNames.Login, {type = 1})
    ---@type LxServerItem
    local serverItem = ModuleCenter.Login:GetLoginServer()
    local loginAccount = ModuleCenter.Login:GetLoginIdentityId()
    local loginGateWayInfo = ModuleCenter.Login:GetLoginGateWayInfo()
    local ip,port
    if loginGateWayInfo then
        ip = loginGateWayInfo.gateway
        port = loginGateWayInfo.port
    else
        ip = serverItem.ip
        port = serverItem.port
    end
    MgrCenter.NetworkMgr:Recreate()
    MgrCenter.NetworkMgr:SetAccount(loginAccount)
    MgrCenter.NetworkMgr:SetConnectPara(serverItem.ip, serverItem.port)
    MgrCenter.NetworkMgr:Connect()
end

---服务器链接成功
function LxLoginCtrl:OnNetConnected()
    self:StopHeartbeat()

    ---请求AuthReq 一直进服务器没到最后步骤次数过多，弹窗断开连接，出提示界面
    local reqCount = ModuleCenter.Login:GetAuthReqTimeoutCount()
    if reqCount >= 4 then
        ModuleCenter.Login:SetAuthReqTimeoutCount(0)
		MgrCenter.NetworkMgr:StopConnect("AuthReq timeout too much !!")        
		ShowPanel(UiNames.SysAlert, {refId = 16})
        ShowBlockMask(false)
        MgrCenter.NetworkMgr:ShowNetBlock(false)
        return
    end

    self:SetLoginStep(_LoginSteps.ServerAuth)
    RefreshPanel(UiNames.Login, {type = 3})

    MgrCenter.HandlerMgr:InitHandlers()
    MgrCenter.ModuleMgr:OnNetConnected()
    -- 账号校验

    ModuleCenter.Login:SetAuthReqTimeoutCount(reqCount + 1)
    HandlerCenter.Login:AuthReq()
end
--- 账号校验结果
function LxLoginCtrl:OnAuthResult(result, version)
    ---跟服务器能正常交互，重置显示重连次数的计数
    MgrCenter.NetworkMgr:ResetShowCounter()

    --- 验证结果标识: 0:验证成功 1:md5校验失败 2:时戳过期  3:参数错误
    if result ~= 0 then
        LogError("AuthResp 验证失败! result=" + result)
        ShowAlert({
            refId =4,
            actionOk = function()
                RestartGame()
            end,
            actionCancel = function()
                self:BackToLogin()
            end,
            args = {a1=tostring(result)}
        })
        return
    end

    if self:CheckResVersionFormServer(version, false, true) then
        return
    end
    --获取服务器时间
    self:SetLoginStep(_LoginSteps.GetServerTime)
    HandlerCenter.Login:ServerTimeReq()
end

