---获取角色信息成功
function LxLoginCtrl:OnGetRoleOk(roleId, identityId, name)
    local isCreateRole = false
    if string.isempty(roleId) or string.len(roleId) < 2 then
        isCreateRole = true
    else
        ModuleCenter.Login:SetRoleId(roleId)
        ModuleCenter.Login:SetRoleName(name)
    end

    if LxGameSettings.isSubpackage and not ModuleCenter.Game.isHasDownLuaAbSubpackage then
        ---未完成luaab 分包预下载，先完成
        CallCsFun(CsFunType.Down, { CsDownType.DownLuaAbSubpackage }, function()
            if self:IsDisposed() then return end
            self:OnDownloadLuaAbSubpackageComplete()
            if isCreateRole then
                self:ToCreateRole()
            else
                self:OnRoleOk()
            end
        end)
    else
        if isCreateRole then
            self:ToCreateRole()
        else
            self:OnRoleOk()
        end
    end
end

---创建角色
function LxLoginCtrl:ToCreateRole()
    self:SetLoginStep(_LoginSteps.CreateRole)
    HandlerCenter.Login:CreateRoleReq()
end

---角色信息获取成功
function LxLoginCtrl:OnRoleOk(isNew)
    local roleId = ModuleCenter.Login:GetRoleId()
    LxPlayerPrefs.LoadPlayerPrefs(roleId)
    LxPlayerPrefs.openGameTime = GetTimestamp()

    FireEvent(EventNames.ON_ROLE_OK, roleId)

    RefreshPanel(UiNames.Login, {type = 4})
    if isNew then
        self._isNew = isNew
        gLxSdkImpl:CallMethod(SdkMethod.DoRoleCreate)
    end
    self:SetLoginStep(_LoginSteps.GetInitData)
    HandlerCenter.Login:LoginReq()
end

function LxLoginCtrl:OnLoginOk()
    ---初始化未初始化的管理器
    gLxMgrCenter:InitAfterLogin()

    --提前加载proto,减少调用时产生的性能消耗
    self:RequireProto()

    --- 通知所有的Handler，登录完成了
    MgrCenter.ModuleMgr:LoginOk()
    MgrCenter.HandlerMgr:LoginOk()

    self:SetLoginStep(_LoginSteps.Done)
    HandlerCenter.Login:LoginSuccessReq()
end

function LxLoginCtrl:EnterGame()
    ---清除authReq 记录次数
    ModuleCenter.Login:SetAuthReqTimeoutCount(0)
    ---清除断线重连显示计数
    MgrCenter.NetworkMgr:ResetShowCounter()

    CtrlCenter.Game:InitAfterLoginGame()
    CtrlCenter.RedPoint:InitAfterLoginGame()
    CtrlCenter.Chat:InitAfterLoginGame()
    CtrlCenter.Guide:InitAfterLoginGame()
    CtrlCenter.Battle:InitAfterLoginGame()

    if MgrCenter.NetworkMgr:IsReconnected() then
        MgrCenter.NetworkMgr:ShowNetBlock(false)
        MgrCenter.NetworkMgr:ResendLostMessages()
        FireEvent(EventNames.NET_RECONNECTED)
        if not MgrCenter.LevelMgr:IsInLevel(LevelNames.Login) then
            self:StartHeartbeat()
            return
        end
    end

    MgrCenter.NetworkMgr:EnableResend()

    gLxSdkImpl:CallMethod(SdkMethod.DoRoleLogin)
    if gLxSdkImpl:CallMethod(SdkMethod.IsGameAnti) then
        CtrlCenter.Copyright:StartCheckOnlineTime()
    end

    CtrlCenter.Main:OnEnterAfterLogin()
end
