function LxLoginCtrl:StartHeartbeat()
    self:StopHeartbeat()
    self:StartTimer("_heartbeat", 5,false,-1,function()
        if MgrCenter.NetworkMgr then
            MgrCenter.NetworkMgr:SendHeartbeat()
        end
    end)
end

function LxLoginCtrl:StopHeartbeat()
    self:StopTimer("_heartbeat")
end
